typedef enum { PARSE_OK, PARSE_OVERFLOW, PARSE_INVALID } parse_result_t;

parse_result_t parse_int(const char *s, int base, long *out) {
    long val = 0;
    int neg = 0;
    const char *p = s;

    if (!s || !out) return PARSE_INVALID;

    while (*p == ' ' || *p == '\t') p++;

    if (*p == '-') { neg = 1; p++; }
    else if (*p == '+') p++;

    if (base == 0) {
        if (*p == '0') {
            if (*(p+1) == 'x' || *(p+1) == 'X') { base = 16; p += 2; }
            else if (*(p+1) == 'b' || *(p+1) == 'B') { base = 2; p += 2; }
            else { base = 8; p++; }
        } else base = 10;
    }

    if (base < 2 || base > 36) return PARSE_INVALID;

    while (*p) {
        int digit;
        if (*p >= '0' && *p <= '9') digit = *p - '0';
        else if (*p >= 'a' && *p <= 'z') digit = *p - 'a' + 10;
        else if (*p >= 'A' && *p <= 'Z') digit = *p - 'A' + 10;
        else break;

        if (digit >= base) return PARSE_INVALID;

        if (__builtin_mul_overflow(val, base, &val)) return PARSE_OVERFLOW;
        if (__builtin_add_overflow(val, digit, &val)) return PARSE_OVERFLOW;
        p++;
    }

    *out = neg ? -val : val;
    return (*p == '\0') ? PARSE_OK : PARSE_INVALID;
}
