typedef enum {
    OP_NOP, OP_PUSH, OP_POP, OP_ADD, OP_SUB, OP_MUL, OP_DIV,
    OP_JMP, OP_JZ, OP_CALL, OP_RET, OP_LOAD, OP_STORE, OP_HALT
} opcode_t;

typedef struct {
    uint32_t regs[16];
    uint32_t pc, sp, bp;
    uint8_t *mem;
    size_t mem_size;
    int running;
} vm_t;

void vm_init(vm_t *vm, uint8_t *mem, size_t sz) {
    memset(vm->regs, 0, sizeof(vm->regs));
    vm->pc = 0;
    vm->sp = sz - 4;
    vm->bp = vm->sp;
    vm->mem = mem;
    vm->mem_size = sz;
    vm->running = 1;
}

uint32_t vm_fetch(vm_t *vm) {
    return *(uint32_t*)(vm->mem + vm->pc);
}

void vm_run(vm_t *vm) {
    while (vm->running) {
        uint32_t instr = vm_fetch(vm);
        uint8_t op = instr & 0xFF;
        uint8_t r1 = (instr >> 8) & 0xF;
        uint8_t r2 = (instr >> 12) & 0xF;
        uint32_t imm = instr >> 16;

        vm->pc += 4;

        switch (op) {
            case OP_NOP: break;
            case OP_PUSH:
                vm->sp -= 4;
                *(uint32_t*)(vm->mem + vm->sp) = vm->regs[r1];
                break;
            case OP_POP:
                vm->regs[r1] = *(uint32_t*)(vm->mem + vm->sp);
                vm->sp += 4;
                break;
            case OP_ADD: vm->regs[r1] = vm->regs[r2] + imm; break;
            case OP_SUB: vm->regs[r1] = vm->regs[r2] - imm; break;
            case OP_MUL: vm->regs[r1] = vm->regs[r2] * imm; break;
            case OP_JMP: vm->pc = imm; break;
            case OP_JZ:  if (!vm->regs[r1]) vm->pc = imm; break;
            case OP_CALL:
                vm->sp -= 4;
                *(uint32_t*)(vm->mem + vm->sp) = vm->pc;
                vm->pc = imm;
                break;
            case OP_RET:
                vm->pc = *(uint32_t*)(vm->mem + vm->sp);
                vm->sp += 4;
                break;
            case OP_LOAD:
                vm->regs[r1] = *(uint32_t*)(vm->mem + vm->regs[r2] + imm);
                break;
            case OP_STORE:
                *(uint32_t*)(vm->mem + vm->regs[r2] + imm) = vm->regs[r1];
                break;
            case OP_HALT: vm->running = 0; break;
        }
    }
}
