typedef struct {
    uint8_t imr;      // Interrupt Mask Register
    uint8_t irr;      // Interrupt Request Register
    uint8_t isr;      // In-Service Register
    uint8_t icw[4];   // Initialization Command Words
    int icw_idx;
    int init_mode;
} pic_t;

typedef struct {
    uint16_t counter[3];
    uint16_t reload[3];
    uint8_t mode[3];
    uint8_t latch_status;
    int output[3];
} pit_t;

void pic_init(pic_t *p) {
    p->imr = 0;
    p->irr = 0;
    p->isr = 0;
    p->icw_idx = 0;
    p->init_mode = 0;
}

uint8_t pic_read(pic_t *p, uint16_t port) {
    if (port == 0x20 || port == 0xA0) return p->irr;
    if (port == 0x21 || port == 0xA1) return p->imr;
    return 0;
}

void pic_write(pic_t *p, uint16_t port, uint8_t val) {
    if (port == 0x20 || port == 0xA0) {
        if (val & 0x10) { p->init_mode = 1; p->icw_idx = 0; }
        if (val == 0x20) { // EOI
            for (int i = 0; i < 8; i++)
                if (p->isr & (1 << i)) { p->isr &= ~(1 << i); break; }
        }
    } else if ((port == 0x21 || port == 0xA1) && !p->init_mode) {
        p->imr = val;
    }
}

int pic_get_irq(pic_t *p) {
    uint8_t pending = p->irr & ~p->imr;
    for (int i = 0; i < 8; i++)
        if (pending & (1 << i)) return i;
    return -1;
}

void pit_tick(pit_t *p) {
    for (int i = 0; i < 3; i++) {
        if (p->counter[i] == 0) {
            p->counter[i] = p->reload[i];
            p->output[i] ^= 1;
        } else {
            p->counter[i]--;
        }
    }
}

void pit_write(pit_t *p, uint16_t port, uint8_t val) {
    if (port == 0x43) {
        int ch = (val >> 6) & 3;
        if (ch == 3) return;
        p->mode[ch] = (val >> 1) & 7;
        p->latch_status = 0;
    } else {
        int ch = (port - 0x40) & 3;
        static int lsb[3] = {0};
        if (!lsb[ch]) { p->reload[ch] = val; lsb[ch] = 1; }
        else { p->reload[ch] |= (val << 8); lsb[ch] = 0; p->counter[ch] = p->reload[ch]; }
    }
}
