#include <stdint.h>

typedef struct {
    uint8_t  e_ident[16];
    uint16_t e_type;
    uint16_t e_machine;
    uint32_t e_version;
    uint64_t e_entry;
    uint64_t e_phoff;
    uint64_t e_shoff;
    uint32_t e_flags;
    uint16_t e_ehsize;
    uint16_t e_phentsize;
    uint16_t e_phnum;
    uint16_t e_shentsize;
    uint16_t e_shnum;
    uint16_t e_shstrndx;
} Elf64_Ehdr;

typedef struct {
    uint32_t p_type;
    uint32_t p_flags;
    uint64_t p_offset;
    uint64_t p_vaddr;
    uint64_t p_paddr;
    uint64_t p_filesz;
    uint64_t p_memsz;
    uint64_t p_align;
} Elf64_Phdr;

#define PT_LOAD 1
#define PF_X 1
#define PF_W 2
#define PF_R 4

int load_elf(void *elf_data, void *(*alloc)(size_t, uint64_t)) {
    Elf64_Ehdr *eh = elf_data;

    if (eh->e_ident[0] != 0x7F || eh->e_ident[1] != 'E' ||
        eh->e_ident[2] != 'L'  || eh->e_ident[3] != 'F')
        return -1;

    if (eh->e_ident[4] != 2 || eh->e_machine != 0x3E)
        return -2;

    Elf64_Phdr *ph = (void*)((char*)elf_data + eh->e_phoff);

    for (int i = 0; i < eh->e_phnum; i++) {
        if (ph[i].p_type != PT_LOAD) continue;

        void *dest = alloc(ph[i].p_memsz, ph[i].p_vaddr);
        if (!dest) return -3;

        memcpy(dest, (char*)elf_data + ph[i].p_offset, ph[i].p_filesz);
        memset(dest + ph[i].p_filesz, 0, ph[i].p_memsz - ph[i].p_filesz);
    }

    return eh->e_entry;
}
