typedef struct {
    char *buf;
    size_t size;
    size_t head;
    size_t tail;
} ring_t;

void ring_init(ring_t *r, void *mem, size_t sz) {
    r->buf = mem;
    r->size = sz;
    r->head = r->tail = 0;
}

int ring_write(ring_t *r, char c) {
    size_t next = (r->head + 1) % r->size;
    if (next == r->tail) return 0;
    r->buf[r->head] = c;
    r->head = next;
    return 1;
}

int ring_read(ring_t *r, char *c) {
    if (r->head == r->tail) return 0;
    *c = r->buf[r->tail];
    r->tail = (r->tail + 1) % r->size;
    return 1;
}

void ring_write_str(ring_t *r, const char *s) {
    while (*s) ring_write(r, *s++);
}
