    for (size_t i = 0; i < st->len; i++)
        if (st->syms[i].addr == addr) return &st->syms[i];
    return NULL;
}

sym_t* symtab_find_name(symtab_t *st, const char *name) {
    for (size_t i = 0; i < st->len; i++)
        if (!strcmp(st->syms[i].name, name)) return &st->syms[i];
    return NULL;
}

void symtab_add(symtab_t *st, uint64_t addr, const char *name) {
    if (st->len >= st->cap) return;
    st->syms[st->len].addr = addr;
    st->syms[st->len].name = strdup(name);
    st->len++;
}
