typedef struct {
    volatile uint32_t lock;
} spinlock_t;

#define SPINLOCK_INIT {0}

static inline void spin_lock(spinlock_t *l) {
    while (atomic_xchg(&l->lock, 1)) {
        while (l->lock) __asm__ volatile ("pause");
    }
}

static inline void spin_unlock(spinlock_t *l) {
    __asm__ volatile ("" ::: "memory");
    l->lock = 0;
}

static inline int spin_trylock(spinlock_t *l) {
    return atomic_xchg(&l->lock, 1) == 0;
}

// Для отключения прерываний при захвате (однопроцессор или критические секции с IRQ)
static inline void spin_lock_irq(spinlock_t *l, uint64_t *flags) {
    __asm__ volatile ("pushfq; popq %0; cli" : "=r"(*flags) :: "memory");
    spin_lock(l);
}

static inline void spin_unlock_irq(spinlock_t *l, uint64_t flags) {
    spin_unlock(l);
    __asm__ volatile ("pushq %0; popfq" :: "r"(flags) : "memory");
}
