#define SLAB_SIZE 4096
#define OBJ_MIN 8

typedef struct slab {
    struct slab *next;
    void *free_list;
    size_t obj_size;
    int free_count;
} slab_t;

typedef struct {
    slab_t *slabs;
    size_t obj_size;
    spinlock_t lock;
} cache_t;

cache_t* cache_create(size_t sz) {
    cache_t *c = kmalloc(sizeof(*c));
    c->obj_size = (sz + 7) & ~7;
    c->slabs = NULL;
    c->lock = SPINLOCK_INIT;
    return c;
}

void* cache_alloc(cache_t *c) {
    spin_lock(&c->lock);
    slab_t *s = c->slabs;
    while (s && s->free_count == 0) s = s->next;

    if (!s) {
        s = page_alloc();
        s->obj_size = c->obj_size;
        s->free_count = (SLAB_SIZE - sizeof(slab_t)) / c->obj_size;
        s->free_list = (char*)s + sizeof(slab_t);

        char *p = s->free_list;
        for (int i = 0; i < s->free_count - 1; i++) {
            *(void**)p = p + c->obj_size;
            p += c->obj_size;
        }
        *(void**)p = NULL;

        s->next = c->slabs;
        c->slabs = s;
    }

    void *obj = s->free_list;
    s->free_list = *(void**)obj;
    s->free_count--;

    spin_unlock(&c->lock);
    return obj;
}

void cache_free(cache_t *c, void *obj) {
    spin_lock(&c->lock);
    slab_t *s = c->slabs;
    while (s && !((char*)obj >= (char*)s && (char*)obj < (char*)s + SLAB_SIZE))
        s = s->next;

    if (s) {
        *(void**)obj = s->free_list;
        s->free_list = obj;
        s->free_count++;
    }
    spin_unlock(&c->lock);
}
