rsdp_t* find_rsdp(void) {
    uint8_t *p = (uint8_t*)0x000E0000;
    while (p < (uint8_t*)0x000FFFFF) {
        if (*(uint64_t*)p == 0x2052545020445352) { // "RSD PTR "
            rsdp_t *rsdp = (rsdp_t*)p;
            uint8_t sum = 0;
            for (int i = 0; i < 20; i++) sum += p[i];
            if (sum == 0) return rsdp;
        }
        p += 16;
    }
    return NULL;
}

void parse_madt(madt_t *madt) {
    uint8_t *ptr = (uint8_t*)(madt + 1);
    uint8_t *end = (uint8_t*)madt + madt->h.length;

    while (ptr < end) {
        uint8_t type = ptr[0];
        uint8_t len = ptr[1];

        if (type == 0) { // Local APIC
            uint8_t cpu_id = ptr[2];
            uint8_t apic_id = ptr[3];
            uint32_t flags = *(uint32_t*)(ptr + 4);
            if (flags & 1) smp_add_cpu(cpu_id, apic_id);
        } else if (type == 1) { // IOAPIC
            uint8_t ioapic_id = ptr[2];
            uint32_t addr = *(uint32_t*)(ptr + 4);
            uint32_t gsi_base = *(uint32_t*)(ptr + 8);
            ioapic_init(ioapic_id, addr, gsi_base);
        }
        ptr += len;
    }
