#define MAX_ORDER 10
#define PAGE_SIZE 4096

typedef struct page {
    struct page *next;
    int order;
    int free;
} page_t;

static page_t *free_lists[MAX_ORDER + 1];
static page_t *pages;
static size_t total_pages;

void buddy_init(void *mem, size_t size) {
    total_pages = size / PAGE_SIZE;
    pages = (page_t*)mem;

    for (int i = 0; i <= MAX_ORDER; i++)
        free_lists[i] = NULL;

    size_t remaining = total_pages;
    size_t idx = 0;

    while (remaining > 0) {
        int order = MAX_ORDER;
        while ((1UL << order) > remaining) order--;

        pages[idx].order = order;
        pages[idx].free = 1;
        pages[idx].next = free_lists[order];
        free_lists[order] = &pages[idx];

        idx += (1 << order);
        remaining -= (1 << order);
    }
}

static page_t* buddy_split(int order) {
    if (order > MAX_ORDER || !free_lists[order]) return NULL;

    page_t *p = free_lists[order];
    free_lists[order] = p->next;

    while (order > 0) {
        order--;
        page_t *buddy = p + (1 << order);
        buddy->order = order;
        buddy->free = 1;
        buddy->next = free_lists[order];
        free_lists[order] = buddy;
    }

    p->free = 0;
    return p;
}

void* buddy_alloc(int order) {
    if (order > MAX_ORDER) return NULL;

    for (int o = order; o <= MAX_ORDER; o++) {
        if (free_lists[o]) {
            page_t *p = buddy_split(o);
            return (void*)((p - pages) * PAGE_SIZE);
        }
    }
    return NULL;
}

void buddy_free(void *ptr) {
    size_t idx = (size_t)ptr / PAGE_SIZE;
    page_t *p = &pages[idx];
    int order = p->order;

    while (order < MAX_ORDER) {
        size_t buddy_idx = idx ^ (1 << order);
        page_t *buddy = &pages[buddy_idx];

        if (!buddy->free || buddy->order != order) break;

        page_t **prev = &free_lists[order];
        while (*prev && *prev != buddy) prev = &(*prev)->next;
        if (*prev) *prev = buddy->next;

        idx &= ~(1 << order);
        p = &pages[idx];
        order++;
    }

    p->order = order;
    p->free = 1;
    p->next = free_lists[order];
    free_lists[order] = p;
}
