typedef enum {
    TOK_EOF, TOK_IDENT, TOK_NUMBER, TOK_STRING, TOK_CHAR,
    TOK_PLUS, TOK_MINUS, TOK_STAR, TOK_SLASH, TOK_PERCENT,
    TOK_EQ, TOK_EQEQ, TOK_BANG, TOK_BANGEQ, TOK_LT, TOK_LTEQ,
    TOK_GT, TOK_GTEQ, TOK_AMP, TOK_AMPAMP, TOK_PIPE, TOK_PIPEPIPE,
    TOK_LPAREN, TOK_RPAREN, TOK_LBRACE, TOK_RBRACE, TOK_LBRACKET, TOK_RBRACKET,
    TOK_SEMICOLON, TOK_COMMA, TOK_DOT, TOK_ARROW,
    TOK_KW_IF, TOK_KW_ELSE, TOK_KW_WHILE, TOK_KW_FOR, TOK_KW_RETURN,
    TOK_KW_INT, TOK_KW_CHAR, TOK_KW_VOID, TOK_KW_STRUCT, TOK_KW_UNION,
    TOK_KW_SIZEOF, TOK_KW_TYPEDEF, TOK_KW_ENUM, TOK_KW_STATIC, TOK_KW_CONST
} token_kind_t;

typedef struct {
    token_kind_t kind;
    char *start;
    int len;
    union {
        long num_val;
        char str_val[256];
    };
} token_t;

typedef struct {
    char *src;
    char *pos;
    int line;
    int col;
} lexer_t;

static int is_alpha(char c) { return (c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || c == '_'; }
static int is_digit(char c) { return c >= '0' && c <= '9'; }
static int is_alnum(char c) { return is_alpha(c) || is_digit(c); }

void lexer_skip_whitespace(lexer_t *l) {
    while (*l->pos == ' ' || *l->pos == '\t' || *l->pos == '\n' || *l->pos == '\r') {
        if (*l->pos == '\n') { l->line++; l->col = 1; }
        else l->col++;
        l->pos++;
    }
}

void lexer_skip_comment(lexer_t *l) {
    if (*l->pos == '/' && *(l->pos + 1) == '/') {
        while (*l->pos && *l->pos != '\n') l->pos++;
    } else if (*l->pos == '/' && *(l->pos + 1) == '*') {
        l->pos += 2;
        while (*l->pos && !(*l->pos == '*' && *(l->pos + 1) == '/')) {
            if (*l->pos == '\n') { l->line++; l->col = 1; }
            l->pos++;
        }
        l->pos += 2;
    }
}

token_t lexer_next(lexer_t *l) {
    token_t tok = {0};

    while (1) {
        lexer_skip_whitespace(l);
        if (*l->pos == '/' && (*(l->pos + 1) == '/' || *(l->pos + 1) == '*')) {
            lexer_skip_comment(l);
            continue;
        }
        break;
    }

    tok.start = l->pos;

    if (*l->pos == '\0') tok.kind = TOK_EOF;
    else if (is_alpha(*l->pos)) {
        while (is_alnum(*l->pos)) l->pos++;
        tok.len = l->pos - tok.start;
        // проверка на ключевые слова
        if (!strncmp(tok.start, "if", tok.len)) tok.kind = TOK_KW_IF;
        else if (!strncmp(tok.start, "else", tok.len)) tok.kind = TOK_KW_ELSE;
        else if (!strncmp(tok.start, "while", tok.len)) tok.kind = TOK_KW_WHILE;
        else if (!strncmp(tok.start, "return", tok.len)) tok.kind = TOK_KW_RETURN;
        else if (!strncmp(tok.start, "int", tok.len)) tok.kind = TOK_KW_INT;
        else tok.kind = TOK_IDENT;
    }
    else if (is_digit(*l->pos)) {
        tok.num_val = 0;
        while (is_digit(*l->pos)) {
            tok.num_val = tok.num_val * 10 + (*l->pos - '0');
            l->pos++;
        }
        tok.kind = TOK_NUMBER;
    }
    else {
        char c = *l->pos++;
        switch (c) {
            case '+': tok.kind = TOK_PLUS; break;
            case '-': tok.kind = (*l->pos == '>') ? (l->pos++, TOK_ARROW) : TOK_MINUS; break;
            case '*': tok.kind = TOK_STAR; break;
            case '/': tok.kind = TOK_SLASH; break;
            case '=': tok.kind = (*l->pos == '=') ? (l->pos++, TOK_EQEQ) : TOK_EQ; break;
            case '!': tok.kind = (*l->pos == '=') ? (l->pos++, TOK_BANGEQ) : TOK_BANG; break;
            case '<': tok.kind = (*l->pos == '=') ? (l->pos++, TOK_LTEQ) : TOK_LT; break;
            case '>': tok.kind = (*l->pos == '=') ? (l->pos++, TOK_GTEQ) : TOK_GT; break;
            case '&': tok.kind = (*l->pos == '&') ? (l->pos++, TOK_AMPAMP) : TOK_AMP; break;
            case '|': tok.kind = (*l->pos == '|') ? (l->pos++, TOK_PIPEPIPE) : TOK_PIPE; break;
            case '(': tok.kind = TOK_LPAREN; break;
            case ')': tok.kind = TOK_RPAREN; break;
            case '{': tok.kind = TOK_LBRACE; break;
            case '}': tok.kind = TOK_RBRACE; break;
            case '[': tok.kind = TOK_LBRACKET; break;
            case ']': tok.kind = TOK_RBRACKET; break;
            case ';': tok.kind = TOK_SEMICOLON; break;
            case ',': tok.kind = TOK_COMMA; break;
            case '.': tok.kind = TOK_DOT; break;
        }
    }

    return tok;
}
