typedef struct ast_node ast_node_t;

typedef ast_node_t* (*prefix_fn)(void);
typedef ast_node_t* (*infix_fn)(ast_node_t*);

typedef struct {
    token_kind_t kind;
    int prec;
    prefix_fn prefix;
    infix_fn infix;
} parse_rule_t;

static parse_rule_t rules[256];

ast_node_t* parse_precedence(int prec) {
    token_t tok = current_token;
    prefix_fn prefix = rules[tok.kind].prefix;
    if (!prefix) { error("Expected expression"); return NULL; }

    ast_node_t *left = prefix();

    while (prec < rules[current_token.kind].prec) {
        tok = current_token;
        infix_fn infix = rules[tok.kind].infix;
        left = infix(left);
    }

    return left;
}

ast_node_t* parse_number(void) {
    ast_node_t *n = new_node(AST_NUMBER);
    n->num_val = current_token.num_val;
    advance();
    return n;
}

ast_node_t* parse_group(void) {
    advance(); // '('
    ast_node_t *expr = parse_precedence(0);
    expect(TOK_RPAREN);
    return expr;
}

ast_node_t* parse_binary(ast_node_t *left) {
    ast_node_t *n = new_node(AST_BINARY);
    n->op = current_token.kind;
    int prec = rules[current_token.kind].prec;
    advance();
    n->left = left;
    n->right = parse_precedence(prec);
    return n;
}

void init_parser(void) {
    rules[TOK_NUMBER] = (parse_rule_t){TOK_NUMBER, 0, parse_number, NULL};
    rules[TOK_LPAREN] = (parse_rule_t){TOK_LPAREN, 0, parse_group, NULL};

    rules[TOK_PLUS]   = (parse_rule_t){TOK_PLUS, 1, NULL, parse_binary};
    rules[TOK_MINUS]  = (parse_rule_t){TOK_MINUS, 1, NULL, parse_binary};
    rules[TOK_STAR]   = (parse_rule_t){TOK_STAR, 2, NULL, parse_binary};
    rules[TOK_SLASH]  = (parse_rule_t){TOK_SLASH, 2, NULL, parse_binary};
    rules[TOK_EQEQ]   = (parse_rule_t){TOK_EQEQ, 0, NULL, parse_binary};
    rules[TOK_BANGEQ] = (parse_rule_t){TOK_BANGEQ, 0, NULL, parse_binary};
    rules[TOK_LT]     = (parse_rule_t){TOK_LT, 0, NULL, parse_binary};
    rules[TOK_GT]     = (parse_rule_t){TOK_GT, 0, NULL, parse_binary};
}
