typedef struct {
    char *buf;
    size_t cap;
    size_t len;
} code_buf_t;

void emit(code_buf_t *cb, const char *fmt, ...) {
    va_list args;
    va_start(args, fmt);
    cb->len += vsnprintf(cb->buf + cb->len, cb->cap - cb->len, fmt, args);
    va_end(args);
}

void gen_expr(code_buf_t *cb, ast_node_t *n) {
    if (!n) return;

    switch (n->kind) {
        case AST_NUMBER:
            emit(cb, "    mov rax, %ld\n", n->num_val);
            break;

        case AST_BINARY:
            gen_expr(cb, n->right);
            emit(cb, "    push rax\n");
            gen_expr(cb, n->left);
            emit(cb, "    pop rcx\n");

            switch (n->op) {
                case TOK_PLUS:  emit(cb, "    add rax, rcx\n"); break;
                case TOK_MINUS: emit(cb, "    sub rax, rcx\n"); break;
                case TOK_STAR:  emit(cb, "    imul rax, rcx\n"); break;
                case TOK_SLASH:
                    emit(cb, "    xor rdx, rdx\n");
                    emit(cb, "    idiv rcx\n");
                    break;
                case TOK_EQEQ:
                    emit(cb, "    cmp rax, rcx\n");
                    emit(cb, "    sete al\n");
                    emit(cb, "    movzx rax, al\n");
                    break;
                case TOK_LT:
                    emit(cb, "    cmp rax, rcx\n");
                    emit(cb, "    setl al\n");
                    emit(cb, "    movzx rax, al\n");
                    break;
                default: break;
            }
            break;
    }
}

void gen_function(code_buf_t *cb, ast_node_t *func) {
    emit(cb, "_start:\n");
    emit(cb, "    push rbp\n");
    emit(cb, "    mov rbp, rsp\n");

    gen_expr(cb, func->body);

    emit(cb, "    mov rdi, rax\n");
    emit(cb, "    mov rax, 60\n");
    emit(cb, "    syscall\n");
}
