typedef struct symbol {
    char *name;
    int type;
    int scope;
    uint64_t addr;
    struct symbol *next;
} symbol_t;

#define HASH_SIZE 1024

typedef struct {
    symbol_t *buckets[HASH_SIZE];
} symtab_t;

static uint32_t hash(const char *s) {
    uint32_t h = 5381;
    while (*s) h = ((h << 5) + h) + *s++;
    return h % HASH_SIZE;
}

symbol_t* symtab_lookup(symtab_t *st, const char *name) {
    uint32_t h = hash(name);
    symbol_t *s = st->buckets[h];
    while (s) {
        if (!strcmp(s->name, name)) return s;
        s = s->next;
    }
    return NULL;
}

void symtab_insert(symtab_t *st, const char *name, int type) {
    uint32_t h = hash(name);
    symbol_t *s = malloc(sizeof(*s));
    s->name = strdup(name);
    s->type = type;
    s->scope = current_scope;
    s->next = st->buckets[h];
    st->buckets[h] = s;
}

void symtab_enter_scope(symtab_t *st) { current_scope++; }

void symtab_leave_scope(symtab_t *st) {
    for (int i = 0; i < HASH_SIZE; i++) {
        symbol_t *prev = NULL;
        symbol_t *s = st->buckets[i];
        while (s) {
            if (s->scope == current_scope) {
                if (prev) prev->next = s->next;
                else st->buckets[i] = s->next;
                free(s->name);
                symbol_t *tmp = s;
                s = s->next;
                free(tmp);
            } else {
                prev = s;
                s = s->next;
            }
        }
    }
    current_scope--;
}
