#define ATA_PRIMARY_DATA    0x1F0
#define ATA_PRIMARY_ERR     0x1F1
#define ATA_PRIMARY_SECCOUNT 0x1F2
#define ATA_PRIMARY_LBA_LO  0x1F3
#define ATA_PRIMARY_LBA_MID 0x1F4
#define ATA_PRIMARY_LBA_HI  0x1F5
#define ATA_PRIMARY_DRIVE   0x1F6
#define ATA_PRIMARY_CMD     0x1F7
#define ATA_PRIMARY_STATUS  0x1F7

#define ATA_CMD_READ        0x20
#define ATA_CMD_WRITE       0x30
#define ATA_SR_BSY          0x80
#define ATA_SR_DRQ          0x08

void ata_wait_bsy(void) {
    while (inb(ATA_PRIMARY_STATUS) & ATA_SR_BSY);
}

void ata_wait_drq(void) {
    while (!(inb(ATA_PRIMARY_STATUS) & ATA_SR_DRQ));
}

int ata_read_sector(uint32_t lba, uint8_t *buf) {
    ata_wait_bsy();

    outb(ATA_PRIMARY_DRIVE, 0xE0 | ((lba >> 24) & 0x0F));
    outb(ATA_PRIMARY_SECCOUNT, 1);
    outb(ATA_PRIMARY_LBA_LO, lba & 0xFF);
    outb(ATA_PRIMARY_LBA_MID, (lba >> 8) & 0xFF);
    outb(ATA_PRIMARY_LBA_HI, (lba >> 16) & 0xFF);
    outb(ATA_PRIMARY_CMD, ATA_CMD_READ);

    ata_wait_bsy();

    if (inb(ATA_PRIMARY_STATUS) & 1) return -1;

    ata_wait_drq();

    for (int i = 0; i < 256; i++) {
        uint16_t val = inw(ATA_PRIMARY_DATA);
        buf[i*2] = val & 0xFF;
        buf[i*2+1] = val >> 8;
    }

    return 0;
}

int ata_write_sector(uint32_t lba, const uint8_t *buf) {
    ata_wait_bsy();

    outb(ATA_PRIMARY_DRIVE, 0xE0 | ((lba >> 24) & 0x0F));
    outb(ATA_PRIMARY_SECCOUNT, 1);
    outb(ATA_PRIMARY_LBA_LO, lba & 0xFF);
    outb(ATA_PRIMARY_LBA_MID, (lba >> 8) & 0xFF);
    outb(ATA_PRIMARY_LBA_HI, (lba >> 16) & 0xFF);
    outb(ATA_PRIMARY_CMD, ATA_CMD_WRITE);

    ata_wait_bsy();
    ata_wait_drq();

    for (int i = 0; i < 256; i++) {
        uint16_t val = buf[i*2] | (buf[i*2+1] << 8);
        outw(ATA_PRIMARY_DATA, val);
    }

    return 0;
}
