#define PML4_RECURSIVE 510
#define PML4_BASE 0xFFFFFF7FBFDFE000UL

uint64_t* pml4 = (uint64_t*)PML4_BASE;

void vmm_map_page(uint64_t phys, uint64_t virt, uint64_t flags) {
    size_t pml4_idx = (virt >> 39) & 0x1FF;
    size_t pdpt_idx = (virt >> 30) & 0x1FF;
    size_t pd_idx   = (virt >> 21) & 0x1FF;
    size_t pt_idx   = (virt >> 12) & 0x1FF;

    uint64_t *pdpt, *pd, *pt;

    if (!(pml4[pml4_idx] & 1)) {
        pdpt = page_alloc();
        pml4[pml4_idx] = (uint64_t)pdpt | 0x3;
    } else {
        pdpt = (uint64_t*)((pml4[pml4_idx] & ~0xFFF) + VIRT_BASE);
    }

    if (!(pdpt[pdpt_idx] & 1)) {
        pd = page_alloc();
        pdpt[pdpt_idx] = (uint64_t)pd | 0x3;
    } else {
        pd = (uint64_t*)((pdpt[pdpt_idx] & ~0xFFF) + VIRT_BASE);
    }

    if (!(pd[pd_idx] & 1)) {
        pt = page_alloc();
        pd[pd_idx] = (uint64_t)pt | 0x3;
    } else {
        pt = (uint64_t*)((pd[pd_idx] & ~0xFFF) + VIRT_BASE);
    }

    pt[pt_idx] = phys | flags | 0x1;
    __asm__ volatile ("invlpg (%0)" :: "r"(virt) : "memory");
}

void vmm_unmap_page(uint64_t virt) {
    size_t pml4_idx = (virt >> 39) & 0x1FF;
    size_t pdpt_idx = (virt >> 30) & 0x1FF;
    size_t pd_idx   = (virt >> 21) & 0x1FF;
    size_t pt_idx   = (virt >> 12) & 0x1FF;

    if (!(pml4[pml4_idx] & 1)) return;
    uint64_t *pdpt = (uint64_t*)((pml4[pml4_idx] & ~0xFFF) + VIRT_BASE);

    if (!(pdpt[pdpt_idx] & 1)) return;
    uint64_t *pd = (uint64_t*)((pdpt[pdpt_idx] & ~0xFFF) + VIRT_BASE);

    if (!(pd[pd_idx] & 1)) return;
    uint64_t *pt = (uint64_t*)((pd[pd_idx] & ~0xFFF) + VIRT_BASE);

    pt[pt_idx] = 0;
    __asm__ volatile ("invlpg (%0)" :: "r"(virt) : "memory");
}
