typedef struct {
    uint8_t thr;  // Transmit Holding Register
    uint8_t rbr;  // Receiver Buffer Register
    uint8_t ier;  // Interrupt Enable Register
    uint8_t iir;  // Interrupt Identification Register
    uint8_t fcr;  // FIFO Control Register
    uint8_t lcr;  // Line Control Register
    uint8_t mcr;  // Modem Control Register
    uint8_t lsr;  // Line Status Register
    uint8_t msr;  // Modem Status Register
    uint8_t scr;  // Scratch Register
    uint8_t dll;  // Divisor Latch LSB
    uint8_t dlm;  // Divisor Latch MSB
    int dlab;
} uart16550_t;

void uart_init(uart16550_t *u) {
    u->lsr = 0x60; // TX empty, RX empty
    u->iir = 0x01; // No interrupt
}

uint8_t uart_read(uart16550_t *u, uint16_t port) {
    port &= 7;
    if (u->dlab) {
        if (port == 0) return u->dll;
        if (port == 1) return u->dlm;
    }
    switch (port) {
        case 0: u->lsr &= ~1; return u->rbr;
        case 1: return u->ier;
        case 2: return u->iir;
        case 3: return u->lcr;
        case 4: return u->mcr;
        case 5: return u->lsr;
        case 6: return u->msr;
        case 7: return u->scr;
    }
    return 0;
}

void uart_write(uart16550_t *u, uint16_t port, uint8_t val) {
    port &= 7;
    if (u->dlab) {
        if (port == 0) { u->dll = val; return; }
        if (port == 1) { u->dlm = val; return; }
    }
    switch (port) {
        case 0:
            u->thr = val;
            putchar(val); // Вывод на экран эмулятора
            u->lsr |= 0x40;
            break;
        case 1: u->ier = val; break;
        case 2: u->fcr = val; break;
        case 3: u->lcr = val; u->dlab = val & 0x80; break;
        case 4: u->mcr = val; break;
        case 7: u->scr = val; break;
    }
}
