void putchar(char c) {
    // write to VGA or serial
    *((volatile char*)0xB8000 + cursor_pos++) = c;
    *((volatile char*)0xB8000 + cursor_pos++) = 0x0F;
}

void print_str(const char *s) {
    while (*s) putchar(*s++);
}

void print_hex(uint64_t n) {
    char buf[17] = {0};
    char *p = buf + 16;
    do {
        int d = n & 0xF;
        *--p = d < 10 ? '0' + d : 'a' + d - 10;
        n >>= 4;
    } while (n);
    print_str(p);
}

void print_dec(int64_t n) {
    char buf[21] = {0};
    char *p = buf + 20;
    int neg = n < 0;
    if (neg) n = -n;
    do {
        *--p = '0' + (n % 10);
        n /= 10;
    } while (n);
    if (neg) *--p = '-';
    print_str(p);
}

void kprintf(const char *fmt, ...) {
    va_list args;
    va_start(args, fmt);

    while (*fmt) {
        if (*fmt != '%') {
            putchar(*fmt++);
            continue;
        }
        fmt++;
        switch (*fmt++) {
            case 's': print_str(va_arg(args, char*)); break;
            case 'c': putchar(va_arg(args, int)); break;
            case 'd': print_dec(va_arg(args, int64_t)); break;
            case 'x': print_hex(va_arg(args, uint64_t)); break;
            case 'p': print_str("0x"); print_hex(va_arg(args, uint64_t)); break;
            case '%': putchar('%'); break;
        }
    }
    va_end(args);
}
