typedef struct slab_cache {
    size_t obj_size;
    void *free_list;
    spinlock_t lock;
} slab_cache_t;

void slab_cache_init(slab_cache_t *c, size_t sz) {
    c->obj_size = (sz + 7) & ~7;
    c->free_list = NULL;
    c->lock = (spinlock_t){0};
}

void* slab_alloc(slab_cache_t *c) {
    spin_lock(&c->lock);

    if (!c->free_list) {
        void *page = page_alloc();
        int obj_count = PAGE_SIZE / c->obj_size;

        for (int i = 0; i < obj_count; i++) {
            void *obj = (char*)page + i * c->obj_size;
            *(void**)obj = c->free_list;
            c->free_list = obj;
        }
    }

    void *obj = c->free_list;
    c->free_list = *(void**)obj;

    spin_unlock(&c->lock);
    return obj;
}

void slab_free(slab_cache_t *c, void *obj) {
    spin_lock(&c->lock);
