typedef struct {
    char *key;
    char *value;
} cmdline_arg_t;

static cmdline_arg_t args[32];
static int arg_count = 0;

void cmdline_parse(char *cmdline) {
    char *p = cmdline;

    while (*p && arg_count < 32) {
        while (*p == ' ') p++;
        if (!*p) break;

        char *key = p;
        char *value = NULL;

        while (*p && *p != ' ' && *p != '=') p++;

        if (*p == '=') {
            *p++ = 0;
            value = p;
            while (*p && *p != ' ') p++;
        }

        if (*p) *p++ = 0;

        args[arg_count].key = key;
        args[arg_count].value = value;
        arg_count++;
    }
}

char* cmdline_get(char *key) {
    for (int i = 0; i < arg_count; i++)
        if (!strcmp(args[i].key, key))
            return args[i].value;
    return NULL;
}

int cmdline_get_bool(char *key) {
    for (int i = 0; i < arg_count; i++)
        if (!strcmp(args[i].key, key))
            return 1;
    return 0;
}
