typedef struct {
    void **data;
    size_t size;
    size_t head;
    size_t tail;
    size_t count;
    spinlock_t lock;
    struct thread *waiting;
} queue_t;

void queue_init(queue_t *q, void *buf, size_t sz) {
    q->data = buf;
    q->size = sz;
    q->head = q->tail = q->count = 0;
    q->lock = (spinlock_t){0};
    q->waiting = NULL;
}

int queue_push(queue_t *q, void *item) {
    spin_lock(&q->lock);

    if (q->count == q->size) {
        spin_unlock(&q->lock);
        return -1;
    }

    q->data[q->head] = item;
    q->head = (q->head + 1) % q->size;
    q->count++;

    if (q->waiting) {
        thread_t *t = q->waiting;
        q->waiting = t->next;
        thread_unblock(t);
    }

    spin_unlock(&q->lock);
    return 0;
}

void* queue_pop(queue_t *q) {
    spin_lock(&q->lock);

    while (q->count == 0) {
        current->next = q->waiting;
        q->waiting = current;
        spin_unlock(&q->lock);
        thread_block();
        spin_lock(&q->lock);
    }

    void *item = q->data[q->tail];
    q->tail = (q->tail + 1) % q->size;
    q->count--;

    spin_unlock(&q->lock);
    return item;
}
