typedef struct {
    thread_t *queues[4];
    thread_t *current;
    spinlock_t lock;
} scheduler_t;

void sched_init(scheduler_t *s) {
    for (int i = 0; i < 4; i++) s->queues[i] = NULL;
    s->current = NULL;
}

void sched_add(scheduler_t *s, thread_t *t) {
    spin_lock(&s->lock);
    int prio = t->priority;
    t->next = s->queues[prio];
    s->queues[prio] = t;
    spin_unlock(&s->lock);
}

thread_t* sched_next(scheduler_t *s) {
    spin_lock(&s->lock);

    for (int i = 3; i >= 0; i--) {
        if (s->queues[i]) {
            thread_t *t = s->queues[i];
            s->queues[i] = t->next;
            spin_unlock(&s->lock);
            return t;
        }
    }

    spin_unlock(&s->lock);
    return NULL;
}

void sched_yield(scheduler_t *s) {
    thread_t *next = sched_next(s);
    if (next && next != s->current) {
        thread_t *old = s->current;
        s->current = next;
        switch_context(&old->ctx, &next->ctx);
    }
}
