    int length;
    char data[];
} string_t;

string_t* string_new(const char *s) {
    int len = strlen(s);
    string_t *str = malloc(sizeof(*str) + len + 1);
    str->refcount = 1;
    str->length = len;
    memcpy(str->data, s, len + 1);
    return str;
