    return s;
}

void string_unref(string_t *s) {
    if (__atomic_sub_fetch(&s->refcount, 1, __ATOMIC_SEQ_CST) == 0)
        free(s);
}

string_t* string_concat(string_t *a, string_t *b) {
    int len = a->length + b->length;
    string_t *s = malloc(sizeof(*s) + len + 1);
    s->refcount = 1;
    s->length = len;
    memcpy(s->data, a->data, a->length);
    memcpy(s->data + a->length, b->data, b->length + 1);
    return s;
