#define PCI_CLASS_STORAGE 0x01
#define PCI_CLASS_NETWORK 0x02
#define PCI_CLASS_DISPLAY 0x03

typedef struct {
    uint8_t bus, dev, func;
    uint16_t vendor, device;
    uint8_t class, subclass, prog_if;
    uint32_t bars[6];
} pci_device_t;

void pci_scan_class(uint8_t class_code, pci_device_t *devs, int *count) {
    *count = 0;

    for (int bus = 0; bus < 256; bus++) {
        for (int dev = 0; dev < 32; dev++) {
            for (int func = 0; func < 8; func++) {
                uint32_t data = pci_read(bus, dev, func, 0);
                if ((data & 0xFFFF) == 0xFFFF) continue;

                uint32_t class_data = pci_read(bus, dev, func, 8);
                uint8_t dev_class = (class_data >> 24) & 0xFF;

                if (dev_class == class_code) {
                    pci_device_t *d = &devs[(*count)++];
                    d->bus = bus;
                    d->dev = dev;
                    d->func = func;
                    d->vendor = data & 0xFFFF;
                    d->device = (data >> 16) & 0xFFFF;
                    d->class = dev_class;
                    d->subclass = (class_data >> 16) & 0xFF;
                    d->prog_if = (class_data >> 8) & 0xFF;

                    for (int i = 0; i < 6; i++) {
                        d->bars[i] = pci_read(bus, dev, func, 0x10 + i*4);
                    }
                }

                uint32_t header = pci_read(bus, dev, func, 0xC);
                if (!(header & 0x800000) || func > 0) break;
            }
        }
    }
}
