typedef struct {
    uint8_t *bitmap;
    size_t total_blocks;
    size_t block_size;
    size_t free_blocks;
    spinlock_t lock;
} bitmap_alloc_t;

void bitmap_init(bitmap_alloc_t *a, void *mem, size_t sz, size_t blk_sz) {
    a->block_size = blk_sz;
    a->total_blocks = sz / blk_sz;
    a->free_blocks = a->total_blocks;
    a->bitmap = mem;
    a->lock = (spinlock_t){0};

    size_t bitmap_sz = (a->total_blocks + 7) / 8;
    memset(a->bitmap, 0, bitmap_sz);
}

void* bitmap_alloc(bitmap_alloc_t *a, size_t blocks) {
    spin_lock(&a->lock);

    for (size_t i = 0; i <= a->total_blocks - blocks; i++) {
        int found = 1;
        for (size_t j = 0; j < blocks; j++) {
            size_t idx = i + j;
            if (a->bitmap[idx / 8] & (1 << (idx % 8))) {
                found = 0;
                break;
            }
        }

        if (found) {
            for (size_t j = 0; j < blocks; j++) {
                size_t idx = i + j;
                a->bitmap[idx / 8] |= (1 << (idx % 8));
            }
            a->free_blocks -= blocks;
            spin_unlock(&a->lock);
            return (void*)((uintptr_t)a->bitmap + 
                          ((a->total_blocks + 7) / 8 * 8) + 
                          i * a->block_size);
        }
    }

    spin_unlock(&a->lock);
    return NULL;
}

void bitmap_free(bitmap_alloc_t *a, void *ptr, size_t blocks) {
    spin_lock(&a->lock);

    uintptr_t start = (uintptr_t)ptr - 
                      ((uintptr_t)a->bitmap + ((a->total_blocks + 7) / 8 * 8));
    size_t idx = start / a->block_size;

    for (size_t j = 0; j < blocks; j++) {
        a->bitmap[(idx + j) / 8] &= ~(1 << ((idx + j) % 8));
    }
    a->free_blocks += blocks;

    spin_unlock(&a->lock);
}
