int exec_elf(void *elf_data, uint64_t *entry, uint64_t *brk) {
    Elf64_Ehdr *eh = elf_data;

    if (eh->e_ident[0] != 0x7F || eh->e_ident[1] != 'E') return -1;
    if (eh->e_ident[4] != 2) return -2;
    if (eh->e_type != 2) return -3;

    *entry = eh->e_entry;
    *brk = 0;

    Elf64_Phdr *ph = (void*)((char*)elf_data + eh->e_phoff);

    for (int i = 0; i < eh->e_phnum; i++) {
        if (ph[i].p_type != 1) continue;

        uint64_t end = ph[i].p_vaddr + ph[i].p_memsz;
        if (end > *brk) *brk = end;

        for (uint64_t j = 0; j < ph[i].p_memsz; j += PAGE_SIZE) {
            uint64_t vaddr = (ph[i].p_vaddr + j) & ~0xFFF;
            void *page = page_alloc();
            vmm_map_page((uint64_t)page, vaddr, 0x7);
        }

        memcpy((void*)ph[i].p_vaddr, 
               (char*)elf_data + ph[i].p_offset, 
               ph[i].p_filesz);
        memset((void*)(ph[i].p_vaddr + ph[i].p_filesz), 0,
               ph[i].p_memsz - ph[i].p_filesz);
    }

    return 0;
}
