typedef struct mem_region {
    uint64_t base;
    uint64_t size;
    uint32_t flags;
    struct mem_region *next;
} mem_region_t;

static mem_region_t *regions = NULL;

void mem_region_add(uint64_t base, uint64_t size, uint32_t flags) {
    mem_region_t *r = kmalloc(sizeof(*r));
    r->base = base;
    r->size = size;
    r->flags = flags;
    r->next = regions;
    regions = r;
}

mem_region_t* mem_region_find(uint64_t addr) {
    mem_region_t *r = regions;
    while (r) {
        if (addr >= r->base && addr < r->base + r->size)
            return r;
        r = r->next;
    }
    return NULL;
}

void mem_region_remove(uint64_t base, uint64_t size) {
    mem_region_t *prev = NULL, *r = regions;
    while (r) {
        if (r->base == base && r->size == size) {
            if (prev) prev->next = r->next;
            else regions = r->next;
            kfree(r);
            return;
        }
        prev = r;
        r = r->next;
    }
}
