typedef struct {
    volatile int locked;
    thread_t *owner;
    thread_t *waiters;
    spinlock_t lock;
} mutex_t;

void mutex_init(mutex_t *m) {
    m->locked = 0;
    m->owner = NULL;
    m->waiters = NULL;
    m->lock = (spinlock_t){0};
}

void mutex_lock(mutex_t *m) {
    spin_lock(&m->lock);

    if (!m->locked) {
        m->locked = 1;
        m->owner = current;
        spin_unlock(&m->lock);
        return;
    }

    current->next = m->waiters;
    m->waiters = current;
    spin_unlock(&m->lock);
    thread_block();
}

void mutex_unlock(mutex_t *m) {
    spin_lock(&m->lock);

    if (m->owner != current) {
        spin_unlock(&m->lock);
        return;
    }

    if (m->waiters) {
        thread_t *t = m->waiters;
        m->waiters = t->next;
        m->owner = t;
        thread_unblock(t);
    } else {
        m->locked = 0;
        m->owner = NULL;
    }

    spin_unlock(&m->lock);
}
