typedef enum { JSON_NULL, JSON_BOOL, JSON_NUMBER, JSON_STRING, JSON_ARRAY, JSON_OBJECT } json_type_t;

typedef struct json_value {
    json_type_t type;
    union {
        int boolean;
        double number;
        char *string;
        struct {
            struct json_value **items;
            int count;
        } array;
        struct {
            char **keys;
            struct json_value **values;
            int count;
        } object;
    };
} json_value_t;

json_value_t* json_parse(char **p) {
    while (**p == ' ' || **p == '\n' || **p == '\t') (*p)++;

    if (**p == '{') {
        (*p)++;
        json_value_t *obj = malloc(sizeof(*obj));
        obj->type = JSON_OBJECT;
        obj->object.keys = NULL;
        obj->object.values = NULL;
        obj->object.count = 0;

        while (**p && **p != '}') {
            while (**p == ' ' || **p == ',') (*p)++;
            if (**p == '}') break;

            json_value_t *key = json_parse(p);
            while (**p == ' ' || **p == ':') (*p)++;
            json_value_t *val = json_parse(p);

            obj->object.count++;
            obj->object.keys = realloc(obj->object.keys, obj->object.count * sizeof(char*));
            obj->object.values = realloc(obj->object.values, obj->object.count * sizeof(json_value_t*));
            obj->object.keys[obj->object.count-1] = key->string;
            obj->object.values[obj->object.count-1] = val;
        }
        (*p)++;
        return obj;
    }

    if (**p == '"') {
        (*p)++;
        char *start = *p;
        while (**p && **p != '"') (*p)++;
        int len = *p - start;
        (*p)++;

        json_value_t *str = malloc(sizeof(*str));
        str->type = JSON_STRING;
        str->string = malloc(len + 1);
        memcpy(str->string, start, len);
        str->string[len] = 0;
        return str;
    }

    if (**p >= '0' && **p <= '9') {
        json_value_t *num = malloc(sizeof(*num));
        num->type = JSON_NUMBER;
        num->number = strtod(*p, p);
        return num;
    }

    return NULL;
}
