        if (breakpoints[i].addr == addr) {
            *(uint8_t*)addr = breakpoints[i].saved_byte;
            breakpoints[i] = breakpoints[--bp_count];
            return 0;
        }
    }
    return -1;
}

void bp_handler(uint64_t addr) {
    for (int i = 0; i < bp_count; i++) {
        if (breakpoints[i].addr == addr - 1) {
            kprintf("Breakpoint hit at 0x%lx\n", addr - 1);
            *(uint8_t*)(addr - 1) = breakpoints[i].saved_byte;
            breakpoints[i].saved_byte = 0xCC;
            debugger_prompt();
