typedef struct pool {
    size_t obj_size;
    void *free_list;
    struct pool *next;
} pool_t;

static pool_t *pools = NULL;
static size_t pool_sizes[] = {8, 16, 32, 64, 128, 256, 512, 1024, 2048};

void pool_init(void) {
    for (int i = 0; i < sizeof(pool_sizes)/sizeof(size_t); i++) {
        pool_t *p = malloc(sizeof(*p));
        p->obj_size = pool_sizes[i];
        p->free_list = NULL;
        p->next = pools;
        pools = p;
    }
}

void* pool_alloc(size_t sz) {
    pool_t *p = pools;
    while (p && p->obj_size < sz) p = p->next;
    if (!p) return malloc(sz);

    if (!p->free_list) {
        void *page = page_alloc();
        int count = PAGE_SIZE / p->obj_size;
        for (int i = 0; i < count; i++) {
            void *obj = (char*)page + i * p->obj_size;
            *(void**)obj = p->free_list;
            p->free_list = obj;
        }
    }

    void *obj = p->free_list;
    p->free_list = *(void**)obj;
    return obj;
}

void pool_free(void *ptr, size_t sz) {
    pool_t *p = pools;
    while (p && p->obj_size < sz) p = p->next;

    if (p && ((uintptr_t)ptr & 0xFFF) == (uintptr_t)ptr % PAGE_SIZE) {
        *(void**)ptr = p->free_list;
        p->free_list = ptr;
    } else {
        free(ptr);
    }
}
