typedef struct free_page {
    struct free_page *next;
    uint64_t count;
} free_page_t;

static free_page_t *free_list = NULL;
static spinlock_t page_lock = {0};

void page_free_list_add(uint64_t base, uint64_t count) {
    spin_lock(&page_lock);

    free_page_t *p = (free_page_t*)base;
    p->count = count;
    p->next = free_list;
    free_list = p;

    spin_unlock(&page_lock);
}

uint64_t page_free_list_alloc(uint64_t count) {
    spin_lock(&page_lock);

    free_page_t *prev = NULL;
    free_page_t *p = free_list;

    while (p) {
        if (p->count >= count) {
            uint64_t addr = (uint64_t)p;

            if (p->count > count) {
                free_page_t *new = (free_page_t*)(addr + count * PAGE_SIZE);
                new->count = p->count - count;
                new->next = p->next;

                if (prev) prev->next = new;
                else free_list = new;
            } else {
                if (prev) prev->next = p->next;
                else free_list = p->next;
            }

            spin_unlock(&page_lock);
            return addr;
        }
        prev = p;
        p = p->next;
    }

    spin_unlock(&page_lock);
    return 0;
}
