typedef struct hash_entry {
    char *key;
    void *value;
    struct hash_entry *next;
} hash_entry_t;

typedef struct {
    hash_entry_t **buckets;
    int size;
    int count;
} hash_t;

hash_t* hash_new(int size) {
    hash_t *h = malloc(sizeof(*h));
    h->size = size;
    h->count = 0;
    h->buckets = calloc(size, sizeof(hash_entry_t*));
    return h;
}

static uint32_t hash_string(const char *s) {
    uint32_t h = 5381;
    while (*s) h = h * 33 + *s++;
    return h;
}

void hash_set(hash_t *h, const char *key, void *value) {
    uint32_t idx = hash_string(key) % h->size;

    hash_entry_t *e = h->buckets[idx];
    while (e) {
        if (!strcmp(e->key, key)) {
            e->value = value;
            return;
        }
        e = e->next;
    }

    e = malloc(sizeof(*e));
    e->key = strdup(key);
    e->value = value;
    e->next = h->buckets[idx];
    h->buckets[idx] = e;
    h->count++;
}

void* hash_get(hash_t *h, const char *key) {
    uint32_t idx = hash_string(key) % h->size;

    hash_entry_t *e = h->buckets[idx];
    while (e) {
        if (!strcmp(e->key, key)) return e->value;
        e = e->next;
    }
    return NULL;
}
