typedef struct task {
    uint64_t rsp;
    uint64_t cr3;
    struct task *next;
    int state;
    int priority;
    uint64_t ticks_left;
} task_t;

static task_t *run_queue = NULL;
static task_t *current_task = NULL;

void task_add(task_t *t) {
    t->next = run_queue;
    run_queue = t;
}

void schedule(void) {
    if (!current_task) {
        current_task = run_queue;
        if (current_task) run_queue = current_task->next;
        else return;
    }

    if (current_task->state == 0 && current_task->ticks_left > 0) {
        current_task->ticks_left--;
        return;
    }

    if (current_task->state == 0) {
        current_task->ticks_left = 10 - current_task->priority;
        task_add(current_task);
    }

    task_t *next = run_queue;
    if (next) {
        run_queue = next->next;

        uint64_t old_rsp;
        __asm__ volatile ("mov %%rsp, %0" : "=r"(old_rsp));
        current_task->rsp = old_rsp;

        current_task = next;

        __asm__ volatile (
            "mov %0, %%cr3\n"
            "mov %1, %%rsp\n"
            : : "r"(current_task->cr3), "r"(current_task->rsp)
        );
    }
}
