#define VGA_WIDTH 80
#define VGA_HEIGHT 25
#define VGA_MEM 0xB8000

static uint16_t *vga = (uint16_t*)VGA_MEM;
static int vga_x = 0, vga_y = 0;
static uint8_t vga_color = 0x0F;

void vga_scroll(void) {
    for (int y = 1; y < VGA_HEIGHT; y++) {
        for (int x = 0; x < VGA_WIDTH; x++) {
            vga[(y-1) * VGA_WIDTH + x] = vga[y * VGA_WIDTH + x];
        }
    }

    for (int x = 0; x < VGA_WIDTH; x++) {
        vga[(VGA_HEIGHT-1) * VGA_WIDTH + x] = (vga_color << 8) | ' ';
    }
}

void vga_putc(char c) {
    if (c == '\n') {
        vga_x = 0;
        vga_y++;
    } else if (c == '\r') {
        vga_x = 0;
    } else if (c == '\b') {
        if (vga_x > 0) vga_x--;
        vga[vga_y * VGA_WIDTH + vga_x] = (vga_color << 8) | ' ';
    } else {
        vga[vga_y * VGA_WIDTH + vga_x] = (vga_color << 8) | c;
        vga_x++;
    }

    if (vga_x >= VGA_WIDTH) {
        vga_x = 0;
        vga_y++;
    }

    if (vga_y >= VGA_HEIGHT) {
        vga_scroll();
        vga_y = VGA_HEIGHT - 1;
    }

    vga_update_cursor(vga_x, vga_y);
}

void vga_update_cursor(int x, int y) {
    uint16_t pos = y * VGA_WIDTH + x;
    outb(0x3D4, 0x0F);
    outb(0x3D5, pos & 0xFF);
    outb(0x3D4, 0x0E);
    outb(0x3D5, (pos >> 8) & 0xFF);
}
