typedef struct block {
    size_t size;
    int free;
    struct block *next;
    struct block *prev;
} block_t;

static block_t *heap_start = NULL;

void kfree(void *ptr) {
    if (!ptr) return;

    block_t *block = (block_t*)ptr - 1;
    block->free = 1;

    if (block->next && block->next->free) {
        block->size += sizeof(block_t) + block->next->size;
        block->next = block->next->next;
        if (block->next) block->next->prev = block;
    }

    if (block->prev && block->prev->free) {
        block->prev->size += sizeof(block_t) + block->size;
        block->prev->next = block->next;
        if (block->next) block->next->prev = block->prev;
    }
}

void* kmalloc(size_t size) {
    if (!heap_start) {
        heap_start = (block_t*)0x200000;
        heap_start->size = 0x100000;
        heap_start->free = 1;
        heap_start->next = NULL;
        heap_start->prev = NULL;
    }

    block_t *curr = heap_start;
    while (curr) {
        if (curr->free && curr->size >= size) {
            if (curr->size > size + sizeof(block_t) + 8) {
                block_t *new = (block_t*)((char*)(curr + 1) + size);
                new->size = curr->size - size - sizeof(block_t);
                new->free = 1;
                new->next = curr->next;
                new->prev = curr;

                if (curr->next) curr->next->prev = new;
                curr->next = new;
                curr->size = size;
            }

            curr->free = 0;
            return curr + 1;
        }
        curr = curr->next;
    }

    return NULL;
}
