void page_fault_handler(uint64_t error_code, uint64_t cr2) {
    uint64_t cr3;
    __asm__ volatile ("mov %%cr3, %0" : "=r"(cr3));

    task_t *task = current_task;

    if (!(error_code & 1)) {
        void *page = page_alloc();
        if (!page) {
            kprintf("Out of memory!\n");
            task_kill(task);
            return;
        }

        vmm_map_page((uint64_t)page, cr2 & ~0xFFF, 0x7);
        return;
    }

    if (error_code & 2) {
        uint64_t *pte = vmm_get_pte(cr2);

        if (*pte & (1ULL << 9)) {
            void *old_page = (void*)(*pte & ~0xFFF);
            void *new_page = page_alloc();

            memcpy(new_page, old_page, PAGE_SIZE);

            *pte = (uint64_t)new_page | 0x7;
            __asm__ volatile ("invlpg (%0)" :: "r"(cr2));

            uint64_t refs = atomic_dec(&page_refs[(uint64_t)old_page / PAGE_SIZE]);
            if (refs == 0) page_free(old_page);

            return;
        }
    }

    kprintf("Segmentation fault at 0x%lx, error: 0x%lx\n", cr2, error_code);
    task_kill(task);
}
