typedef struct {
    int argc;
    char **argv;
    int optind;
    char *optarg;
    int opterr;
} getopt_t;

void getopt_init(getopt_t *g, int argc, char **argv) {
    g->argc = argc;
    g->argv = argv;
    g->optind = 1;
    g->optarg = NULL;
    g->opterr = 1;
}

int getopt_next(getopt_t *g, const char *optstring) {
    static int sp = 1;

    if (sp == 1) {
        if (g->optind >= g->argc || g->argv[g->optind][0] != '-' || g->argv[g->optind][1] == '\0')
            return -1;
    }

    char c = g->argv[g->optind][sp];
    const char *cp = strchr(optstring, c);

    if (c == ':' || !cp) {
        if (g->opterr) kprintf(": illegal option -- %c\n", c);
        if (g->argv[g->optind][++sp] == '\0') {
            g->optind++;
            sp = 1;
        }
        return '?';
    }

    if (cp[1] == ':') {
        if (g->argv[g->optind][sp+1] != '\0') {
            g->optarg = &g->argv[g->optind][sp+1];
        } else {
            g->optind++;
            if (g->optind >= g->argc) {
                if (g->opterr) kprintf(": option requires an argument -- %c\n", c);
                sp = 1;
                return ':';
            }
            g->optarg = g->argv[g->optind];
        }
        g->optind++;
        sp = 1;
    } else {
        if (g->argv[g->optind][++sp] == '\0') {
            sp = 1;
            g->optind++;
        }
        g->optarg = NULL;
    }

    return c;
}
