typedef struct {
    uint8_t *buf;
    size_t size;
    size_t read_idx;
    size_t write_idx;
} ring_buffer_t;

void ring_init(ring_buffer_t *rb, void *mem, size_t sz) {
    rb->buf = mem;
    rb->size = sz;
    rb->read_idx = 0;
    rb->write_idx = 0;
}

size_t ring_available(ring_buffer_t *rb) {
    if (rb->write_idx >= rb->read_idx)
        return rb->write_idx - rb->read_idx;
    else
        return rb->size - rb->read_idx + rb->write_idx;
}

size_t ring_free(ring_buffer_t *rb) {
    return rb->size - ring_available(rb) - 1;
}

int ring_write(ring_buffer_t *rb, uint8_t byte) {
    if (ring_free(rb) == 0) return -1;

    rb->buf[rb->write_idx] = byte;
    rb->write_idx = (rb->write_idx + 1) % rb->size;
    return 0;
}

int ring_read(ring_buffer_t *rb, uint8_t *byte) {
    if (ring_available(rb) == 0) return -1;

    *byte = rb->buf[rb->read_idx];
    rb->read_idx = (rb->read_idx + 1) % rb->size;
    return 0;
}

size_t ring_write_bulk(ring_buffer_t *rb, const uint8_t *data, size_t len) {
    size_t written = 0;
    while (written < len && ring_write(rb, data[written]) == 0)
        written++;
    return written;
}

size_t ring_read_bulk(ring_buffer_t *rb, uint8_t *data, size_t len) {
    size_t read = 0;
    while (read < len && ring_read(rb, &data[read]) == 0)
        read++;
    return read;
}
