    "r14", "r15", "rsp", "rbp"
};

typedef struct {
    int used;
    int spilled;
} reg_alloc_t;

static reg_alloc_t regs[16];

void reg_alloc_init(void) {
    for (int i = 0; i < 16; i++) {
        regs[i].used = 0;
        regs[i].spilled = 0;
    }
}

reg_t reg_alloc(void) {
    for (int i = 0; i < 12; i++) {
        if (!regs[i].used && !regs[i].spilled) {
            regs[i].used = 1;
            return i;
        }
    }
    return REG_NONE;
}

void reg_free(reg_t r) {
    if (r != REG_NONE) {
        regs[r].used = 0;
    }
}

reg_t reg_alloc_specific(reg_t r) {
    if (!regs[r].used && !regs[r].spilled) {
        regs[r].used = 1;
        return r;
    }

    reg_t spill = REG_NONE;
    for (int i = 0; i < 12; i++) {
        if (regs[i].used) {
            spill = i;
            break;
        }
    }

    if (spill != REG_NONE) {
        regs[spill].spilled = 1;
        regs[spill].used = 0;
        regs[r].used = 1;
        return r;
    }

    return REG_NONE;
}
