typedef struct {
    uint64_t regs[16];
    uint64_t rip;
    uint64_t rflags;
    uint8_t *mem;
    size_t mem_size;
} cpu_t;

void cpu_init(cpu_t *c, uint8_t *mem, size_t sz) {
    memset(c->regs, 0, sizeof(c->regs));
    c->rip = 0;
    c->rflags = 0x2;
    c->mem = mem;
    c->mem_size = sz;
}

uint8_t cpu_fetch8(cpu_t *c) {
    return c->mem[c->rip++];
}

uint32_t cpu_fetch32(cpu_t *c) {
    uint32_t v = *(uint32_t*)(c->mem + c->rip);
    c->rip += 4;
    return v;
}

void cpu_step(cpu_t *c) {
    uint8_t op = cpu_fetch8(c);

    switch (op) {
        case 0x48:
            op = cpu_fetch8(c);
            if (op == 0x89) {
                uint8_t modrm = cpu_fetch8(c);
                uint8_t src = (modrm >> 3) & 7;
                uint8_t dst = modrm & 7;
                if ((modrm >> 6) == 3) {
                    c->regs[dst] = c->regs[src];
                }
            }
            break;

        case 0x50 ... 0x57:
            c->regs[REG_RSP] -= 8;
            *(uint64_t*)(c->mem + c->regs[REG_RSP]) = c->regs[op - 0x50];
            break;

        case 0x58 ... 0x5F:
            c->regs[op - 0x58] = *(uint64_t*)(c->mem + c->regs[REG_RSP]);
            c->regs[REG_RSP] += 8;
            break;

        case 0xB8 ... 0xBF:
            c->regs[op - 0xB8] = cpu_fetch32(c);
            break;

        case 0xC3:
            c->rip = *(uint64_t*)(c->mem + c->regs[REG_RSP]);
            c->regs[REG_RSP] += 8;
            break;

        case 0xE9:
            int32_t offset = cpu_fetch32(c);
            c->rip += offset;
            break;
    }
}
