void bitmap_set(uint8_t *bitmap, size_t bit) {
    bitmap[bit / 8] |= (1 << (bit % 8));
}

void bitmap_clear(uint8_t *bitmap, size_t bit) {
    bitmap[bit / 8] &= ~(1 << (bit % 8));
}

int bitmap_test(uint8_t *bitmap, size_t bit) {
    return bitmap[bit / 8] & (1 << (bit % 8));
}

size_t bitmap_find_first_zero(uint8_t *bitmap, size_t size) {
    for (size_t i = 0; i < size * 8; i++) {
        if (!bitmap_test(bitmap, i)) return i;
    }
    return (size_t)-1;
}

size_t bitmap_find_first_set(uint8_t *bitmap, size_t size) {
    for (size_t i = 0; i < size * 8; i++) {
        if (bitmap_test(bitmap, i)) return i;
    }
    return (size_t)-1;
}

size_t bitmap_find_contiguous(uint8_t *bitmap, size_t size, size_t count) {
    size_t found = 0;
    size_t start = 0;

    for (size_t i = 0; i < size * 8; i++) {
        if (!bitmap_test(bitmap, i)) {
            if (found == 0) start = i;
            found++;
            if (found == count) return start;
        } else {
            found = 0;
        }
    }

    return (size_t)-1;
}
