typedef struct {
    char *section;
    char *key;
    char *value;
} ini_entry_t;

void ini_parse(const char *data, ini_entry_t *entries, int *count) {
    char line[256];
    char section[64] = "";
    const char *p = data;

    *count = 0;

    while (*p) {
        char *l = line;
        while (*p && *p != '\n') *l++ = *p++;
        *l = '\0';
        if (*p) p++;

        char *s = line;
        while (*s == ' ' || *s == '\t') s++;

        if (*s == ';' || *s == '#' || *s == '\0') continue;

        if (*s == '[') {
            s++;
            char *end = strchr(s, ']');
            if (end) {
                *end = '\0';
                strcpy(section, s);
            }
            continue;
        }

        char *eq = strchr(s, '=');
        if (!eq) continue;

        *eq = '\0';
        char *key = s;
        char *value = eq + 1;

        while (*key == ' ' || *key == '\t') key++;
        char *kend = key + strlen(key) - 1;
        while (kend > key && (*kend == ' ' || *kend == '\t')) *kend-- = '\0';

        while (*value == ' ' || *value == '\t') value++;
        char *vend = value + strlen(value) - 1;
        while (vend > value && (*vend == ' ' || *vend == '\t')) *vend-- = '\0';

        entries[*count].section = strdup(section);
        entries[*count].key = strdup(key);
        entries[*count].value = strdup(value);
        (*count)++;
    }
}
