typedef struct obj {
    enum { OBJ_NIL, OBJ_NUM, OBJ_SYM, OBJ_CONS } type;
    union {
        long num;
        char *sym;
        struct { struct obj *car; struct obj *cdr; } cons;
    };
} obj_t;

obj_t* make_num(long n) {
    obj_t *o = malloc(sizeof(*o));
    o->type = OBJ_NUM;
    o->num = n;
    return o;
}

obj_t* make_sym(char *s) {
    obj_t *o = malloc(sizeof(*o));
    o->type = OBJ_SYM;
    o->sym = strdup(s);
    return o;
}

obj_t* cons(obj_t *car, obj_t *cdr) {
    obj_t *o = malloc(sizeof(*o));
    o->type = OBJ_CONS;
    o->cons.car = car;
    o->cons.cdr = cdr;
    return o;
}

obj_t* eval(obj_t *expr, obj_t *env) {
    if (expr->type == OBJ_NUM) return expr;

    if (expr->type == OBJ_SYM) {
        obj_t *val = env_lookup(env, expr->sym);
        return val ? val : expr;
    }

    if (expr->type == OBJ_CONS) {
        obj_t *op = expr->cons.car;
        obj_t *args = expr->cons.cdr;

        if (op->type == OBJ_SYM) {
            if (!strcmp(op->sym, "+")) {
                long sum = 0;
                while (args->type != OBJ_NIL) {
                    obj_t *arg = eval(args->cons.car, env);
                    sum += arg->num;
                    args = args->cons.cdr;
                }
                return make_num(sum);
            }

            if (!strcmp(op->sym, "if")) {
                obj_t *cond = eval(args->cons.car, env);
                args = args->cons.cdr;
                obj_t *then_expr = args->cons.car;
                args = args->cons.cdr;
                obj_t *else_expr = args->cons.car;

                return eval(cond->num ? then_expr : else_expr, env);
            }
        }
    }

    return expr;
}
