long strtol_base(const char *str, char **endptr, int base) {
    long result = 0;
    int sign = 1;

    while (*str == ' ' || *str == '\t') str++;

    if (*str == '-') {
        sign = -1;
        str++;
    } else if (*str == '+') {
        str++;
    }

    if (base == 0) {
        if (*str == '0') {
            if (*(str+1) == 'x' || *(str+1) == 'X') {
                base = 16;
                str += 2;
            } else if (*(str+1) == 'b' || *(str+1) == 'B') {
                base = 2;
                str += 2;
            } else {
                base = 8;
                str++;
            }
        } else {
            base = 10;
        }
    }

    while (*str) {
        int digit;
        if (*str >= '0' && *str <= '9')
            digit = *str - '0';
        else if (*str >= 'a' && *str <= 'z')
            digit = *str - 'a' + 10;
        else if (*str >= 'A' && *str <= 'Z')
            digit = *str - 'A' + 10;
        else
            break;

        if (digit >= base) break;

        result = result * base + digit;
        str++;
    }

    if (endptr) *endptr = (char*)str;
    return sign * result;
}

char* ltostr(long num, char *str, int base) {
    char *p = str;
    char *p1, *p2;
    unsigned long unum;

    if (num < 0 && base == 10) {
        *p++ = '-';
        unum = -num;
    } else {
        unum = num;
    }

    p1 = p;
    do {
        int digit = unum % base;
        *p++ = (digit < 10) ? '0' + digit : 'a' + digit - 10;
        unum /= base;
    } while (unum);

    *p = '\0';

    p2 = p - 1;
    while (p1 < p2) {
        char tmp = *p1;
        *p1++ = *p2;
        *p2-- = tmp;
    }

    return str;
}
