typedef struct {
    int priority;
    void *data;
} pq_node_t;

typedef struct {
    pq_node_t *nodes;
    int size;
    int capacity;
} pq_t;

void pq_init(pq_t *pq, int cap) {
    pq->nodes = malloc(sizeof(pq_node_t) * cap);
    pq->size = 0;
    pq->capacity = cap;
}

void pq_swap(pq_node_t *a, pq_node_t *b) {
    pq_node_t tmp = *a;
    *a = *b;
    *b = tmp;
}

void pq_heapify_up(pq_t *pq, int idx) {
    while (idx > 0) {
        int parent = (idx - 1) / 2;
        if (pq->nodes[parent].priority <= pq->nodes[idx].priority)
            break;
        pq_swap(&pq->nodes[parent], &pq->nodes[idx]);
        idx = parent;
    }
}

void pq_heapify_down(pq_t *pq, int idx) {
    while (1) {
        int left = 2 * idx + 1;
        int right = 2 * idx + 2;
        int smallest = idx;

        if (left < pq->size && 
            pq->nodes[left].priority < pq->nodes[smallest].priority)
            smallest = left;

        if (right < pq->size && 
            pq->nodes[right].priority < pq->nodes[smallest].priority)
            smallest = right;

        if (smallest == idx) break;

        pq_swap(&pq->nodes[idx], &pq->nodes[smallest]);
        idx = smallest;
    }
}

int pq_push(pq_t *pq, int priority, void *data) {
    if (pq->size >= pq->capacity) return -1;

    pq->nodes[pq->size].priority = priority;
    pq->nodes[pq->size].data = data;
    pq_heapify_up(pq, pq->size);
    pq->size++;

    return 0;
}

void* pq_pop(pq_t *pq, int *priority) {
    if (pq->size == 0) return NULL;

    void *data = pq->nodes[0].data;
    if (priority) *priority = pq->nodes[0].priority;

    pq->size--;
    pq->nodes[0] = pq->nodes[pq->size];
    pq_heapify_down(pq, 0);

    return data;
}
