typedef struct timer {
    uint64_t expires;
    void (*callback)(void*);
    void *arg;
    struct timer *next;
    int periodic;
    uint64_t interval;
} timer_t;

static timer_t *timer_list = NULL;
static uint64_t jiffies = 0;

void timer_init(void) {
    timer_list = NULL;
    jiffies = 0;
}

void timer_add(timer_t *timer) {
    timer_t **pp = &timer_list;

    while (*pp && (*pp)->expires <= timer->expires)
        pp = &(*pp)->next;

    timer->next = *pp;
    *pp = timer;
}

void timer_del(timer_t *timer) {
    timer_t **pp = &timer_list;

    while (*pp) {
        if (*pp == timer) {
            *pp = timer->next;
            return;
        }
        pp = &(*pp)->next;
    }
}

void timer_tick(void) {
    jiffies++;

    while (timer_list && timer_list->expires <= jiffies) {
        timer_t *t = timer_list;
        timer_list = t->next;

        t->callback(t->arg);

        if (t->periodic) {
            t->expires = jiffies + t->interval;
            timer_add(t);
        }
    }
}

void timer_set(timer_t *t, uint64_t ms, void (*cb)(void*), void *arg) {
    t->expires = jiffies + ms;
    t->callback = cb;
    t->arg = arg;
    t->periodic = 0;
    timer_add(t);
}

void timer_set_periodic(timer_t *t, uint64_t ms, void (*cb)(void*), void *arg) {
    t->expires = jiffies + ms;
    t->callback = cb;
    t->arg = arg;
    t->periodic = 1;
    t->interval = ms;
    timer_add(t);
}
