typedef struct {
    char *buf;
    size_t size;
    size_t written;
} printf_ctx_t;

static void printf_putc(printf_ctx_t *ctx, char c) {
    if (ctx->written < ctx->size - 1) {
        ctx->buf[ctx->written] = c;
    }
    ctx->written++;
}

static void printf_puts(printf_ctx_t *ctx, const char *s) {
    while (*s) printf_putc(ctx, *s++);
}

static void printf_num(printf_ctx_t *ctx, uint64_t num, int base, int sign) {
    char buf[32];
    char *p = buf + sizeof(buf) - 1;
    *p = '\0';

    if (sign && (int64_t)num < 0) {
        printf_putc(ctx, '-');
        num = -(int64_t)num;
    }

    do {
        int digit = num % base;
        *--p = (digit < 10) ? '0' + digit : 'a' + digit - 10;
        num /= base;
    } while (num);

    printf_puts(ctx, p);
}

int vsnprintf(char *buf, size_t size, const char *fmt, va_list args) {
    printf_ctx_t ctx = {buf, size, 0};

    while (*fmt) {
        if (*fmt != '%') {
            printf_putc(&ctx, *fmt++);
            continue;
        }

        fmt++;

        switch (*fmt++) {
            case 's':
                printf_puts(&ctx, va_arg(args, char*));
                break;
            case 'c':
                printf_putc(&ctx, va_arg(args, int));
                break;
            case 'd':
            case 'i':
                printf_num(&ctx, va_arg(args, int64_t), 10, 1);
                break;
            case 'u':
                printf_num(&ctx, va_arg(args, uint64_t), 10, 0);
                break;
            case 'x':
                printf_num(&ctx, va_arg(args, uint64_t), 16, 0);
                break;
            case 'p':
                printf_puts(&ctx, "0x");
                printf_num(&ctx, va_arg(args, uint64_t), 16, 0);
                break;
            case '%':
                printf_putc(&ctx, '%');
                break;
            case 'l':
                if (*fmt == 'd' || *fmt == 'i' || *fmt == 'u' || *fmt == 'x') {
                    fmt++;
                    printf_num(&ctx, va_arg(args, uint64_t), 
                              *fmt == 'x' ? 16 : 10, *fmt != 'u');
                }
                break;
        }
    }

    if (size > 0) ctx.buf[ctx.written < size ? ctx.written : size - 1] = '\0';

    return ctx.written;
}

int snprintf(char *buf, size_t size, const char *fmt, ...) {
    va_list args;
    va_start(args, fmt);
    int ret = vsnprintf(buf, size, fmt, args);
    va_end(args);
    return ret;
}
