#define MOUSE_IRQ 12
#define MOUSE_PORT 0x60
#define MOUSE_STATUS 0x64
#define MOUSE_CMD 0x64

static int mouse_x = 0, mouse_y = 0;
static int mouse_buttons = 0;

void mouse_wait(uint8_t type) {
    int timeout = 100000;
    if (type == 0) {
        while (timeout-- && !(inb(MOUSE_STATUS) & 1));
    } else {
        while (timeout-- && (inb(MOUSE_STATUS) & 2));
    }
}

void mouse_write(uint8_t val) {
    mouse_wait(1);
    outb(MOUSE_CMD, 0xD4);
    mouse_wait(1);
    outb(MOUSE_PORT, val);
}

uint8_t mouse_read(void) {
    mouse_wait(0);
    return inb(MOUSE_PORT);
}

void mouse_handler(void) {
    static uint8_t cycle = 0;
    static uint8_t bytes[3];

    uint8_t status = inb(MOUSE_STATUS);
    if (!(status & 0x20)) return;

    uint8_t data = mouse_read();

    switch (cycle) {
        case 0:
            if (!(data & 0x08)) return;
            bytes[0] = data;
            cycle++;
            break;
        case 1:
            bytes[1] = data;
            cycle++;
            break;
        case 2:
            bytes[2] = data;

            mouse_buttons = bytes[0] & 0x07;

            int dx = bytes[1];
            if (bytes[0] & 0x10) dx |= 0xFFFFFF00;

            int dy = bytes[2];
            if (bytes[0] & 0x20) dy |= 0xFFFFFF00;

            mouse_x += dx;
            mouse_y -= dy;

            if (mouse_x < 0) mouse_x = 0;
            if (mouse_y < 0) mouse_y = 0;
            if (mouse_x >= VGA_WIDTH * 8) mouse_x = VGA_WIDTH * 8 - 1;
            if (mouse_y >= VGA_HEIGHT * 8) mouse_y = VGA_HEIGHT * 8 - 1;

            cycle = 0;
            break;
    }
}

void mouse_init(void) {
    mouse_wait(1);
    outb(MOUSE_CMD, 0xA8);

    mouse_wait(1);
    outb(MOUSE_CMD, 0x20);
    uint8_t status = mouse_read() | 2;

    mouse_wait(1);
    outb(MOUSE_CMD, 0x60);
    mouse_wait(1);
    outb(MOUSE_PORT, status);

    mouse_write(0xF6);
    mouse_read();

    mouse_write(0xF4);
    mouse_read();

    irq_register(MOUSE_IRQ, mouse_handler);
}
