    int child_count;
} ast_node_t;

ast_node_t* parse_rule(grammar_t *g, const char *rule_name, const char **input);

ast_node_t* parse_sequence(grammar_t *g, char **symbols, int count, const char **input) {
    ast_node_t *node = malloc(sizeof(*node));
    node->type = "seq";
    node->children = malloc(sizeof(ast_node_t*) * count);
    node->child_count = 0;

    const char *saved = *input;

    for (int i = 0; i < count; i++) {
        ast_node_t *child = parse_rule(g, symbols[i], input);
        if (!child) {
            *input = saved;
            free(node->children);
            free(node);
            return NULL;
        }
        node->children[node->child_count++] = child;
    }

    return node;
}

ast_node_t* parse_rule(grammar_t *g, const char *rule_name, const char **input) {
    if (rule_name[0] == '\'' && rule_name[strlen(rule_name)-1] == '\'') {
        char term = rule_name[1];
        if (**input == term) {
            (*input)++;
            ast_node_t *node = malloc(sizeof(*node));
            node->type = "term";
            node->value = malloc(2);
            node->value[0] = term;
            node->value[1] = '\0';
            node->children = NULL;
            node->child_count = 0;
            return node;
        }
        return NULL;
    }

    rule_t *r = NULL;
    for (int i = 0; i < g->rule_count; i++) {
        if (!strcmp(g->rules[i].name, rule_name)) {
            r = &g->rules[i];
            break;
        }
    }

    if (!r) return NULL;

    for (int i = 0; i < r->prod_count; i++) {
        char *prod = r->productions[i];
        char *symbols[16];
        int sym_count = 0;

        char *p = prod;
        while (*p) {
            while (*p == ' ') p++;
            if (!*p) break;

            if (*p == '\'') {
                p++;
                char *sym = malloc(4);
                sym[0] = '\'';
                sym[1] = *p;
                sym[2] = '\'';
                sym[3] = '\0';
                symbol sym_count = sym;
                p += 2;
            } else {
                char *start = p;
                while (*p && *p != ' ') p++;
                int len = p - start;
                char *sym = malloc(len + 1);
                memcpy(sym, start, len);
                sym[len] = '\0';
                symbols[sym_count++] = sym;
            }
        }

        ast_node_t *node = parse_sequence(g, symbols, sym_count, input);

        for (int j = 0; j < sym_count; j++) free(symbols[j]);

        if (node) {
            node->type = r->name;
            return node;
        }
    }

    return NULL;
}
