size_t rle_compress(const uint8_t *input, size_t in_len, uint8_t *output) {
    size_t out_pos = 0;

    for (size_t i = 0; i < in_len; i++) {
        uint8_t byte = input[i];
        size_t count = 1;

        while (i + count < in_len && input[i + count] == byte && count < 255)
            count++;

        output[out_pos++] = byte;
        output[out_pos++] = (uint8_t)count;

        i += count - 1;
    }

    return out_pos;
}

size_t rle_decompress(const uint8_t *input, size_t in_len, uint8_t *output) {
    size_t out_pos = 0;

    for (size_t i = 0; i < in_len; i += 2) {
        uint8_t byte = input[i];
        uint8_t count = input[i + 1];

        for (int j = 0; j < count; j++)
            output[out_pos++] = byte;
    }

    return out_pos;
}
