int parse_int(const char *s, long *out) {
    long val = 0;
    int sign = 1;
    if (!s || !out) return -1;
    while (*s == ' ' || *s == '\t') s++;
    if (*s == '-') { sign = -1; s++; }
    else if (*s == '+') s++;
    if (*s < '0' || *s > '9') return -2;
    while (*s >= '0' && *s <= '9') {
        int digit = *s - '0';
        if (val > (0x7FFFFFFFFFFFFFFFL - digit) / 10) return -3;
        val = val * 10 + digit;
        s++;
    }
    if (*s != '\0') return -4;
    *out = val * sign;
    return 0;
}

int parse_int_auto(const char *s, long *out) {
    long val = 0;
    int sign = 1;
    int base = 10;
    if (!s || !out) return -1;
    while (*s == ' ' || *s == '\t') s++;
    if (*s == '-') { sign = -1; s++; }
    else if (*s == '+') s++;
    if (*s == '0') {
        s++;
        if (*s == 'x' || *s == 'X') { base = 16; s++; }
        else if (*s == 'b' || *s == 'B') { base = 2; s++; }
        else { base = 8; }
    }
    while (*s) {
        int digit;
        if (*s >= '0' && *s <= '9') digit = *s - '0';
        else if (*s >= 'a' && *s <= 'f') digit = *s - 'a' + 10;
        else if (*s >= 'A' && *s <= 'F') digit = *s - 'A' + 10;
        else break;
        if (digit >= base) return -2;
        if (__builtin_mul_overflow(val, base, &val)) return -3;
        if (__builtin_add_overflow(val, digit, &val)) return -3;
        s++;
    }
    *out = val * sign;
    return 0;
}

static long parse_digits(const char *s, int base, int *err) {
    if (!*s) return 0;
    int digit;
    if (*s >= '0' && *s <= '9') digit = *s - '0';
    else if (*s >= 'a' && *s <= 'f') digit = *s - 'a' + 10;
    else if (*s >= 'A' && *s <= 'F') digit = *s - 'A' + 10;
    else { *err = 1; return 0; }
    if (digit >= base) { *err = 1; return 0; }
    long rest = parse_digits(s + 1, base, err);
    if (*err) return 0;
    return rest * base + digit;
}

int parse_int_rec(const char *s, long *out) {
    int sign = 1, err = 0;
    while (*s == ' ') s++;
    if (*s == '-') { sign = -1; s++; }
    if (*s < '0' || *s > '9') return -1;
    long val = parse_digits(s, 10, &err);
    if (err) return -2;
    *out = val * sign;
    return 0;
}

typedef enum { ST_START, ST_SIGN, ST_DIGIT, ST_HEX_PREFIX, ST_HEX, ST_OCT, ST_BIN, ST_DONE, ST_ERR } parse_state_t;

int parse_int_fsm(const char *s, long *out) {
    parse_state_t st = ST_START;
    long val = 0;
    int sign = 1, base = 10;

    for (const char *p = s; *p; p++) {
        switch (st) {
            case ST_START:
                if (*p == ' ') continue;
                if (*p == '-') { sign = -1; st = ST_SIGN; }
                else if (*p == '+') st = ST_SIGN;
                else if (*p == '0') st = ST_HEX_PREFIX;
                else if (*p >= '1' && *p <= '9') { val = *p - '0'; st = ST_DIGIT; }
                else return -1;
                break;
            case ST_SIGN:
                if (*p == '0') st = ST_HEX_PREFIX;
                else if (*p >= '1' && *p <= '9') { val = *p - '0'; st = ST_DIGIT; }
                else return -2;
                break;
            case ST_HEX_PREFIX:
                if (*p == 'x' || *p == 'X') { base = 16; st = ST_HEX; }
                else if (*p == 'b' || *p == 'B') { base = 2; st = ST_BIN; }
                else { base = 8; val = *p - '0'; st = ST_OCT; }
                break;
            case ST_DIGIT:
                if (*p >= '0' && *p <= '9') val = val * 10 + (*p - '0');
                else return -3;
                break;
            case ST_HEX:
                if ((*p >= '0' && *p <= '9') || (*p >= 'a' && *p <= 'f') || (*p >= 'A' && *p <= 'F')) {
                    int d = (*p >= 'a') ? *p - 'a' + 10 : (*p >= 'A') ? *p - 'A' + 10 : *p - '0';
                    val = val * 16 + d;
                } else return -3;
                break;
            case ST_OCT:
                if (*p >= '0' && *p <= '7') val = val * 8 + (*p - '0');
                else return -3;
                break;
            case ST_BIN:
                if (*p == '0' || *p == '1') val = val * 2 + (*p - '0');
                else return -3;
                break;
            default: return -4;
        }
    }
    *out = val * sign;
    return 0;
}

int parse_float(const char *s, float *out) {
    float result = 0.0f;
    float fraction = 0.1f;
    int sign = 1;
    int exp_sign = 1;
    int exponent = 0;
    int state = 0;

    if (!s || !out) return -1;
    while (*s == ' ') s++;
    if (*s == '-') { sign = -1; s++; }
    else if (*s == '+') s++;

    while (*s) {
        char c = *s++;
        if (c >= '0' && c <= '9') {
            if (state == 0) result = result * 10.0f + (c - '0');
            else if (state == 1) { result += (c - '0') * fraction; fraction *= 0.1f; }
            else if (state == 2) exponent = exponent * 10 + (c - '0');
        } else if (c == '.') {
            if (state != 0) return -2;
            state = 1;
        } else if (c == 'e' || c == 'E') {
            if (state == 2) return -2;
            state = 2;
            if (*s == '-') { exp_sign = -1; s++; }
            else if (*s == '+') s++;
        } else return -3;
    }

    while (exponent--) {
        if (exp_sign > 0) result *= 10.0f;
        else result *= 0.1f;
    }

    *out = sign * result;
    return 0;
}

int parse_hex_to_bytes(const char *hex, uint8_t *out, size_t out_len, size_t *written) {
    size_t len = 0;
    uint8_t byte = 0;
    int nibble = 0;

    for (const char *p = hex; *p; p++) {
        char c = *p;
        uint8_t val;

        if (c >= '0' && c <= '9') val = c - '0';
        else if (c >= 'a' && c <= 'f') val = c - 'a' + 10;
        else if (c >= 'A' && c <= 'F') val = c - 'A' + 10;
        else if (c == ' ' || c == '-' || c == ':') continue;
        else return -1;

        if (nibble == 0) {
            byte = val << 4;
            nibble = 1;
        } else {
            byte |= val;
            if (len < out_len) out[len] = byte;
            len++;
            nibble = 0;
        }
    }

    if (nibble == 1) return -2;
    *written = len;
    return 0;
}
